import type { ClientOptions } from 'hot-shots';
import type { MeliStatsD } from '@meli/statsd';

type StatsDConfig = Exclude<ClientOptions, 'host' | 'prefix'>;

declare global {
  namespace Nordic {
    interface Config {
      /**
       * The solution is already configured to track to datadog as described in [Metrics Specification](https://nordic.adminml.com/docs/api/Nordic%20Modules/frontend-statsd#metrics-specification),
       * so there's no need for you to touch any configuration unless you really need some custom behaviour.
       *
       * Only `globalTags` and `suffix` options can be configured.
       *
       * @see {@link https://nordic.adminml.com/docs/api/Nordic%20Modules/frontend-statsd#configuration | Documentation}
       */
      statsd?: StatsDConfig;
    }
  }
}

interface StatsDExport extends MeliStatsD {
  /**
   * Module to track custom metrics from your server using Datadog
   * @deprecated This module is deprecated. Please use the new `@meli/statsd` package instead.
   *
   * @see {@link https://nordic.adminml.com/docs/migration-guides/modules/statsd/migrate-to-meli-statsd | Migration Guide}
   * @example
   * import { statsd } from 'nordic/statsd';
   *
   * const tags = { foo: 'bar' };
   * statsd.increment('my_metric', tags);
   */
  statsd: MeliStatsD;
}

/**
 * @deprecated Default export is now deprecated in favour of named exports.
 * Please read the documentation on how to import `statsd`, or the example below.
 *
 * @see {@link https://nordic.adminml.com/docs/api/Nordic%20Modules/frontend-statsd | Documentation}
 * @example
 * import { statsd } from 'nordic/statsd';
 */
declare const clientInstance: StatsDExport;
export = clientInstance;
